sql:
SELECT AVG(noise_level) AS avg_noise_level_across_experiments
FROM (
    SELECT ec.experiment_id, c.noise_level
    FROM experiment_channels ec
    JOIN eeg_channels c ON ec.channel_id = c.channel_id
) AS experiment_noise_levels;

SELECT name, type, AVG(impedance) AS avg_impedance
FROM eeg_channels
GROUP BY name, type;

external_knowledge:
- 'mature adults' refers to individuals older than 25; 
- 'beginning of 2022' corresponds to the date '2022-01-01'; 
- 'noisiest to quietest' refers to the ordering by average noise level in descending order.

- The term "most channels" refers to the highest count of distinct channel IDs; 
- "most subjects" corresponds to the highest count of distinct subject IDs; 
- "lowest average impedance" implies the smallest average impedance value across channels within an experiment.
